import pytest
import uuid

def test_add_duplicate_account_returns_409(auth_client, existing_beneficiary_account):
    payload = {
        "account_number": existing_beneficiary_account,
        "name": "Duplicate Bob"
    }
    headers = {"Idempotency-Key": str(uuid.uuid4())}

    resp = auth_client.post("/beneficiaries", json=payload, headers=headers)

    assert resp.status_code == 409
    body = resp.json()
    assert "error" in body or "code" in body, "409 body must contain error details"
    error_value = body.get("error", body.get("code", ""))
    assert "DUPLICATE" in str(error_value).upper(), (
        f"Expected DUPLICATE error code, got: {error_value}"
    )
